fn render_tab(id: ScreenId, is_active: bool, frame: &mut Frame, area: Rect) {
    let style = if is_active {
        // Active: Bold white on screen's accent color
        Style::new()
            .fg(fg::PRIMARY)
            .bg(accent_for(id))
            .bold()
