+    fn detect_system_locale_prefers_lc_all() {
+        with_env(&[("LC_ALL", Some("fr_FR.UTF-8")), ("LANG", Some("en_US.UTF-8"))], || {
+            assert_eq!(detect_system_locale(), "fr-FR");
+        });
+    }
